import type { ProjectState } from '../models/projectState';

// ── Shared helpers ────────────────────────────────────────────────────────────

/** Converts artifact-id (e.g. "my-app") to PascalCase class name (e.g. "MyApp"). */
export function toClassName(artifactId: string): string {
  return artifactId
    .split(/[-_]/)
    .filter(Boolean)
    .map((s) => s.charAt(0).toUpperCase() + s.slice(1))
    .join('');
}

/** Standard warning comment for files NOT generated by the real Initializr (R10). */
const WARNING_COMMENT = `/*
 * Arquivo gerado automaticamente pelo TADS Spring Initializr customizado (versão didática).
 * ATENÇÃO: Este arquivo NÃO é gerado pelo Spring Initializr oficial.
 */`;

// ── Application.java ──────────────────────────────────────────────────────────

export function generateApplication(state: ProjectState, hash: string): string {
  const className = toClassName(state.artifact);
  return `// hash-identificacao: ${hash}
package ${state.packageName};

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class ${className}Application {

\tpublic static void main(String[] args) {
\t\tSpringApplication.run(${className}Application.class, args);
\t}

}
`;
}

